import{_ as n,H as t,f as s,i as l}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"网络深入系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"../networkLearning/00-写作计划.md","filePath":"../networkLearning/00-写作计划.md","lastUpdated":1778496697000}'),e={name:"../networkLearning/00-写作计划.md"};function i(o,a,r,p,d,c){return t(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="网络深入系列写作计划" tabindex="-1">网络深入系列写作计划 <a class="header-anchor" href="#网络深入系列写作计划" aria-label="Permalink to &quot;网络深入系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第一类「补完整知识图」第三项,⭐⭐⭐⭐。 webLearning 浅讲了 HTTP / Cookie / CORS,backendLearning 第 55 章把 TCP/TLS/HTTP 粗扫一遍——但<strong>真要深挖到 RFC 级</strong>,做网关、做中间件、扛 DDoS、调 P99,得开独立系列。 本系列定位:<strong>进阶补课</strong>——假设你会用 HTTP API、能写后端服务,但不一定懂包怎么走、TCP 握手怎么实现、TLS 1.3 凭什么 1 RTT、QUIC 解决了什么、eBPF 能干什么。<strong>40 章一次讲透</strong>。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>七层结构,从「包视角」到「工程实战」:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础与心智模型(协议栈 / 抓包 / 链路层)</span></span>
<span class="line"><span>   → 网络层(IP / 路由 / ICMP / NAT)</span></span>
<span class="line"><span>   → 传输层(UDP / TCP / 拥塞 / MPTCP)</span></span>
<span class="line"><span>   → 安全层(密码学 / TLS 1.2 / 1.3 / mTLS / PKI)</span></span>
<span class="line"><span>   → 应用层(HTTP/1.1/2/3 / QUIC / WebSocket / WebRTC / DNS)</span></span>
<span class="line"><span>   → 内核网络(socket / epoll / io_uring / eBPF / XDP / DPDK)</span></span>
<span class="line"><span>   → 工程实战(Nginx / Envoy / CDN / WAF / 抓包 / 排障)</span></span></code></pre></div><p><strong>这个系列不是 RFC 翻译</strong>——RFC 太密、术语门槛太高;<strong>本系列偏&quot;工程师视角&quot;</strong>:每个协议都对应一个真实的&quot;性能问题或者诡异 bug&quot;,学完能直接用在排错和调优。</p><p>不抠每个字段——<strong>而是讲清楚&quot;协议设计的取舍、演进的根本原因、生产中怎么调&quot;</strong>——你写后端 / 中间件 / 网关时必须懂的网络层。</p><hr><h2 id="篇目-40-篇" tabindex="-1">篇目(40 篇) <a class="header-anchor" href="#篇目-40-篇" aria-label="Permalink to &quot;篇目(40 篇)&quot;">​</a></h2><h3 id="第一层-基础与心智模型-01-05" tabindex="-1">第一层:基础与心智模型(01-05) <a class="header-anchor" href="#第一层-基础与心智模型-01-05" aria-label="Permalink to &quot;第一层:基础与心智模型(01-05)&quot;">​</a></h3><ul><li>[x] 01 网络学习路线总览(为什么、四层模型、心智三视角)</li><li>[x] 02 协议栈与封装(包从应用层到链路层走过的路)</li><li>[x] 03 抓包入门(tcpdump + Wireshark + tshark + mitmproxy)</li><li>[x] 04 网络心智三视角(包视角 / 时序视角 / 状态机视角)</li><li>[x] 05 链路层(Ethernet / VLAN / WiFi / ARP)</li></ul><h3 id="第二层-网络层-06-10" tabindex="-1">第二层:网络层(06-10) <a class="header-anchor" href="#第二层-网络层-06-10" aria-label="Permalink to &quot;第二层:网络层(06-10)&quot;">​</a></h3><ul><li>[x] 06 IPv4 详解(头格式 / 分片 / TTL / 校验和)</li><li>[x] 07 IPv6 与过渡(地址类型 / 邻居发现 / 双栈 / 6to4)</li><li>[x] 08 ICMP 与 ping / traceroute(echo / TTL exceeded / 黑洞)</li><li>[x] 09 路由原理(静态路由 / RIP / OSPF / BGP)</li><li>[x] 10 NAT / 子网掩码 / CIDR(NAT 类型 / 端口耗尽)</li></ul><h3 id="第三层-传输层-11-16" tabindex="-1">第三层:传输层(11-16) <a class="header-anchor" href="#第三层-传输层-11-16" aria-label="Permalink to &quot;第三层:传输层(11-16)&quot;">​</a></h3><ul><li>[x] 11 UDP 详解(头格式 / 适用场景 / UDP 之上的协议)</li><li>[x] 12 TCP 三次握手与四次挥手(状态机 / TIME_WAIT / 半连接队列)</li><li>[x] 13 TCP 流量控制与拥塞控制(窗口 / 慢启动 / CUBIC / BBR)</li><li>[x] 14 TCP 高级特性(SACK / 快重传 / Nagle / Delayed ACK / keepalive)</li><li>[x] 15 MPTCP 与 SCTP(多路径 / 多流 / 何时用)</li><li>[x] 16 TCP 调优实战(缓冲区 / 队列 / sysctl 调参 / BBR 上线)</li></ul><h3 id="第四层-tls-与密码学-17-21" tabindex="-1">第四层:TLS 与密码学(17-21) <a class="header-anchor" href="#第四层-tls-与密码学-17-21" aria-label="Permalink to &quot;第四层:TLS 与密码学(17-21)&quot;">​</a></h3><ul><li>[x] 17 密码学基础(对称 / 非对称 / Hash / HMAC / 椭圆曲线)</li><li>[x] 18 TLS 1.2 详解(握手 / 套件 / Session ID / Session Ticket)</li><li>[x] 19 TLS 1.3 详解(0-RTT / PSK / KeyShare / 删了什么)</li><li>[x] 20 mTLS / 双向认证(零信任 / SPIFFE / 服务网格)</li><li>[x] 21 PKI / 证书 / 自建 CA(X.509 / CT / 证书链)</li></ul><h3 id="第五层-http-演进-22-26" tabindex="-1">第五层:HTTP 演进(22-26) <a class="header-anchor" href="#第五层-http-演进-22-26" aria-label="Permalink to &quot;第五层:HTTP 演进(22-26)&quot;">​</a></h3><ul><li>[x] 22 HTTP/1.1 深度(管线 / Keep-Alive / 队头阻塞 / 分块编码)</li><li>[x] 23 HTTP/2(帧 / 流 / 多路复用 / HPACK / 优先级)</li><li>[x] 24 HTTP/3 与 QUIC(UDP 之上的可靠传输 / 0-RTT / 连接迁移)</li><li>[x] 25 WebSocket 内部(升级握手 / 帧格式 / 心跳 / 压缩扩展)</li><li>[x] 26 WebRTC 实战(SDP / ICE / STUN / TURN / DataChannel)</li></ul><h3 id="第六层-dns-体系-27-29" tabindex="-1">第六层:DNS 体系(27-29) <a class="header-anchor" href="#第六层-dns-体系-27-29" aria-label="Permalink to &quot;第六层:DNS 体系(27-29)&quot;">​</a></h3><ul><li>[x] 27 DNS 协议(递归 vs 迭代 / 记录类型 / EDNS0 / 报文格式)</li><li>[x] 28 DoT / DoH / DNSSEC(加密 DNS / 防劫持)</li><li>[x] 29 DNS 性能优化(本地缓存 / 预热 / Anycast / GSLB)</li></ul><h3 id="第七层-linux-内核网络-30-33" tabindex="-1">第七层:Linux 内核网络(30-33) <a class="header-anchor" href="#第七层-linux-内核网络-30-33" aria-label="Permalink to &quot;第七层:Linux 内核网络(30-33)&quot;">​</a></h3><ul><li>[x] 30 socket 编程(BSD socket / 选项 / 半关闭 / SO_REUSEPORT)</li><li>[x] 31 epoll 在网络的应用(LT / ET / 惊群 / 一万连接架构)</li><li>[x] 32 io_uring 与高性能网络(零 syscall 网络栈)</li><li>[x] 33 eBPF / XDP / DPDK(内核可编程 / 用户态网络栈)</li></ul><h3 id="第八层-反向代理-lb-cdn-34-36" tabindex="-1">第八层:反向代理 / LB / CDN(34-36) <a class="header-anchor" href="#第八层-反向代理-lb-cdn-34-36" aria-label="Permalink to &quot;第八层:反向代理 / LB / CDN(34-36)&quot;">​</a></h3><ul><li>[x] 34 Nginx 深度(事件模型 / 配置精要 / 调优 / Lua)</li><li>[x] 35 Envoy 与服务网格(数据面 / xDS / Filter Chain)</li><li>[x] 36 负载均衡 / CDN 调度(L4 vs L7 / 一致性哈希 / 边缘缓存)</li></ul><h3 id="第九层-安全与防御-37-38" tabindex="-1">第九层:安全与防御(37-38) <a class="header-anchor" href="#第九层-安全与防御-37-38" aria-label="Permalink to &quot;第九层:安全与防御(37-38)&quot;">​</a></h3><ul><li>[x] 37 WAF / DDoS 防御(SYN Flood / CC 攻击 / 限流策略)</li><li>[x] 38 渗透测试入门(端口扫描 / 抓 token / 中间人攻击)</li></ul><h3 id="第十层-抓包-压测-排障-39-40" tabindex="-1">第十层:抓包 + 压测 + 排障(39-40) <a class="header-anchor" href="#第十层-抓包-压测-排障-39-40" aria-label="Permalink to &quot;第十层:抓包 + 压测 + 排障(39-40)&quot;">​</a></h3><ul><li>[x] 39 抓包高级与压测(BPF 过滤 / Wireshark 分析 / wrk / h2load)</li><li>[x] 40 网络排障方法论(分层定位 / 看时序 / 看状态机)</li></ul><hr><h2 id="完结-2026-05-10" tabindex="-1">完结(2026/05/10) <a class="header-anchor" href="#完结-2026-05-10" aria-label="Permalink to &quot;完结(2026/05/10)&quot;">​</a></h2><p>40 篇全部完成,跟原计划完全一致。下一步建议:</p><ul><li><strong>配合做一个真实项目串起来</strong>:自建 Nginx/Envoy 反代 → 抓包对照 → 上 BBR/io_uring → 加 mTLS → HTTP/3 切流量,把 11-21 + 30-36 跑成肌肉记忆</li><li><strong>不熟的章节回头翻</strong>:出抖动 / RST / 握手失败时,第一反应应该是翻 40 排障方法论 → 按&quot;分层 + 三视角&quot;定位,而不是从头硬猜</li><li><strong>和 osLearning + algorithmLearning + systemDesign 互相串</strong>:本系列只覆盖网络栈,前两者补 IO 模型 / 限流 / 一致性哈希,systemDesign 补多机房 / 异地多活,合起来才是完整后端 / SRE 视角</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>HTTP 状态码 / Cookie / CORS</td><td>webLearning ✅</td><td>不重复,只讲 HTTP 协议本身的演进</td></tr><tr><td>TCP/TLS/HTTP 调优概念</td><td>backendLearning/55 ✅</td><td>同话题展开到 RFC 细节 + 内核实现</td></tr><tr><td>服务网格(Istio / Linkerd)</td><td>backendLearning/32/60 ✅</td><td>不重复,讲 Envoy 数据面 + xDS + mTLS</td></tr><tr><td>CDN / 对象存储</td><td>backendLearning/45 ✅</td><td>不重复,讲 CDN 调度算法 + 边缘缓存</td></tr><tr><td>epoll / io_uring</td><td>osLearning/21/22 ✅</td><td>不重复,只讲在网络栈里的应用</td></tr><tr><td>限流算法</td><td>algorithmLearning/24 ✅</td><td>不重复,讲 WAF / DDoS 用到时直接引</td></tr><tr><td>一致性哈希</td><td>algorithmLearning/25 ✅</td><td>不重复,讲 CDN 调度时直接引</td></tr><tr><td>渗透 / Web 安全</td><td>webLearning(35 篇浅讲)</td><td>互补,讲传输层 + 网络层的安全攻防</td></tr><tr><td>分布式 / 多机房</td><td>systemDesign ✅</td><td>不重复,只讲网络层的&quot;为什么慢&quot;</td></tr></tbody></table><hr><h2 id="写作模板" tabindex="-1">写作模板 <a class="header-anchor" href="#写作模板" aria-label="Permalink to &quot;写作模板&quot;">​</a></h2><p>每篇遵守&quot;为什么 → 是什么 → 怎么用 → 何时不该用&quot;的四段式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 为什么有这个协议 / 设计</span></span>
<span class="line"><span>   - 上一代有什么缺陷</span></span>
<span class="line"><span>   - 业界为什么逼出新的标准</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 协议格式 / 关键字段</span></span>
<span class="line"><span>   - 报文结构 ASCII 图</span></span>
<span class="line"><span>   - 关键字段的&quot;为什么这么设计&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 工程视角怎么用 / 怎么调</span></span>
<span class="line"><span>   - curl / openssl / dig / tcpdump 实操</span></span>
<span class="line"><span>   - sysctl / 配置文件调参</span></span>
<span class="line"><span>   - 真实案例 (P99 抖、握手慢、连不上)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 何时不该用 / 坑在哪</span></span>
<span class="line"><span>   - 性能边界 / 兼容性</span></span>
<span class="line"><span>   - 常见 bug</span></span>
<span class="line"><span>   - 替代方案</span></span></code></pre></div><p>不堆 RFC 全文——<strong>只贴关键字段图和命令行</strong>,让读者「知道这一层在干嘛 + 抓包能看出来」就够了。</p><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-05  心智:看完知道&quot;网络在工程师眼里到底是什么 + 会抓包&quot;</span></span>
<span class="line"><span>06-10  网络层:IP / 路由 / NAT,做后端 / 做网关必懂</span></span>
<span class="line"><span>11-16  传输层:**最值钱的一层**,P99 / 重传 / 拥塞全在这</span></span>
<span class="line"><span>17-21  TLS:HTTPS 时代的硬通货,mTLS / 服务网格全在这</span></span>
<span class="line"><span>22-26  HTTP:**第二值钱**,API / 网关 / Web 全在这</span></span>
<span class="line"><span>27-29  DNS:被低估的瓶颈,99% 慢启动来自这</span></span>
<span class="line"><span>30-33  内核网络:把抽象拉到最底,真懂&quot;快在哪&quot;</span></span>
<span class="line"><span>34-36  代理 / LB / CDN:工程实战,网关 / SRE 必懂</span></span>
<span class="line"><span>37-38  安全:扛攻击的基本功</span></span>
<span class="line"><span>39-40  排障:把前 38 篇串起来</span></span></code></pre></div><p><strong>一个硬指标</strong>:看完 11-16 + 17-21 这 11 篇,你应该能在白板前讲清楚:</p><ul><li>&quot;为什么 TLS 1.3 比 1.2 少一个 RTT&quot;</li><li>&quot;为什么 BBR 在公网比 CUBIC 抗丢包,但内网两者差不多&quot;</li><li>&quot;为什么我的服务 P99 抖动来自 TIME_WAIT 撑爆 socket 表&quot;</li></ul><p>能讲清楚一题这个系列就值了。</p><hr><h2 id="工具栈" tabindex="-1">工具栈 <a class="header-anchor" href="#工具栈" aria-label="Permalink to &quot;工具栈&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>工具</th></tr></thead><tbody><tr><td><strong>抓包</strong></td><td>tcpdump / Wireshark / tshark / mitmproxy</td></tr><tr><td><strong>客户端</strong></td><td>curl / openssl s_client / nghttp / quiche-client</td></tr><tr><td><strong>DNS</strong></td><td>dig / drill / nslookup / dog</td></tr><tr><td><strong>路由 / ICMP</strong></td><td>ping / traceroute / mtr / tracepath</td></tr><tr><td><strong>socket</strong></td><td>ss / netstat / lsof / strace</td></tr><tr><td><strong>性能 / 压测</strong></td><td>iperf3 / netperf / wrk / h2load</td></tr><tr><td><strong>eBPF</strong></td><td>bcc / bpftrace / cilium</td></tr><tr><td><strong>TLS 调试</strong></td><td>testssl.sh / sslscan / ssllabs.com</td></tr><tr><td><strong>代理 / LB</strong></td><td>Nginx / Envoy / HAProxy</td></tr></tbody></table><blockquote><p>装一份本地 Nginx + Wireshark,每讲一个协议自己抓一次包对照——<strong>这是入门的唯一姿势</strong>。</p></blockquote><hr><h2 id="反对的写法" tabindex="-1">反对的写法 <a class="header-anchor" href="#反对的写法" aria-label="Permalink to &quot;反对的写法&quot;">​</a></h2><p>这个系列<strong>不写</strong>这些东西,见到了就是写错了:</p><ol><li>「逐字段翻译 RFC」——RFC 自己就在那儿,这里讲取舍和坑</li><li>「先讲个故事 / 个人情怀」——直接进重点</li><li>罗列命令但不解释——每个命令配场景</li><li>「这是面试常考」——真懂了面试自然过,不是来刷题的</li><li>抄&quot;图解 HTTP&quot;或&quot;网络是怎样连接的&quot;——那两本都好,这里只补它们没讲透的工程细节</li><li>不画图就讲握手 / 状态机 / 帧——<strong>这些东西不画 ASCII 永远讲不清楚</strong></li><li>不抓包就讲协议——纸上谈兵,失去本系列灵魂</li></ol><hr><h2 id="代码-命令风格" tabindex="-1">代码 / 命令风格 <a class="header-anchor" href="#代码-命令风格" aria-label="Permalink to &quot;代码 / 命令风格&quot;">​</a></h2><ul><li>抓包命令统一用 <code>tcpdump</code> / <code>tshark</code>(Linux 通用)</li><li>客户端测试统一用 <code>curl</code> / <code>openssl s_client</code> / <code>dig</code></li><li>配置示例统一用 Nginx(用得最多)</li><li>内核调参统一用 <code>sysctl</code> / <code>/proc/sys/net/</code></li><li>所有命令贴出来都能直接复制运行</li></ul><hr><h2 id="预计时间线" tabindex="-1">预计时间线 <a class="header-anchor" href="#预计时间线" aria-label="Permalink to &quot;预计时间线&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础 + 网络层(01-10)   → 约 1-2 周</span></span>
<span class="line"><span>传输 + TLS(11-21)      → 约 2 周(TCP 调优最慢)</span></span>
<span class="line"><span>HTTP + DNS(22-29)      → 约 1-2 周</span></span>
<span class="line"><span>内核 + 代理(30-36)     → 约 1-2 周</span></span>
<span class="line"><span>安全 + 排障(37-40)     → 约 1 周</span></span></code></pre></div><p>跟规划里的节奏建议一致:<strong>不建议连开新系列</strong>,写这个系列时建议配合&quot;自建 Nginx 反代 + 抓包对照&quot;做实操闭环。</p>`,63)])])}const g=n(e,[["render",i]]);export{u as __pageData,g as default};
